proof:
induction s with
| leaf =>
  match leaf_data_tree with
  | LeafData.leaf a =>
    simp only [buildMerkleTree, buildMerkleTree_with_hash, runWithOracle]
    <;> try { tauto }
    <;> try { aesop }
| internal s_left s_right left_ih right_ih =>
  match leaf_data_tree with
  | LeafData.internal left right =>
    simp only [buildMerkleTree, buildMerkleTree_with_hash, runWithOracle] at *
    <;> try { tauto }
    <;> try { aesop }

